// src/QrUtilities.js

import React, { useState, useCallback, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import QRCode from 'qrcode';

// ── Static configs ────────────────────────────────────────────────────────────
const sectionAnim  = { initial: { opacity: 0, y: 40 }, whileInView: { opacity: 1, y: 0 }, viewport: { once: true, amount: 0.1 }, transition: { duration: 0.5 } };
const headerAnim   = { initial: { opacity: 0, y: 16 }, whileInView: { opacity: 1, y: 0 }, viewport: { once: true }, transition: { duration: 0.4 } };
const labelAnim    = { initial: { opacity: 0, x: -16 }, whileInView: { opacity: 1, x: 0 }, viewport: { once: true }, transition: { duration: 0.4 } };
const underlineAnim= { initial: { scaleX: 0, originX: 0 }, whileInView: { scaleX: 1 }, viewport: { once: true }, transition: { duration: 0.5, delay: 0.2 } };
const tabAnim      = { initial: { opacity: 0, y: 6 }, animate: { opacity: 1, y: 0 }, exit: { opacity: 0, y: -6 }, transition: { duration: 0.15 } };

const PARTICLES = [
  { width: 7, height: 7, top: '8%',  left: '4%',  duration: 4,   delay: 0   },
  { width: 9, height: 9, top: '78%', left: '95%', duration: 6,   delay: 1.5 },
];

const INPUT_CLASS = "w-full px-4 py-3 rounded-xl border-2 border-gray-200 dark:border-purple-500/20 bg-gray-50 dark:bg-[#0f0f1a] text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 text-sm outline-none focus:border-purple-500 transition-colors duration-200";

// ── QR generators — module level ──────────────────────────────────────────────
const generateQrCanvas = async (text, size = 256) => {
  const canvas = await QRCode.toCanvas(document.createElement('canvas'), text, {
    width:  size, margin: 2,
    color:  { dark: '#1a1a2e', light: '#ffffff' },
    errorCorrectionLevel: 'M',
  });
  return canvas.toDataURL('image/png');
};

const generateQrSvg = (text) => QRCode.toString(text, {
  type: 'svg', margin: 2,
  color: { dark: '#1a1a2e', light: '#ffffff' },
  errorCorrectionLevel: 'M',
});

const triggerDownload = (href, filename) => {
  const a = document.createElement('a');
  a.href = href; a.download = filename;
  document.body.appendChild(a); a.click();
  document.body.removeChild(a);
};

// ── QR grid — CSS ─────────────────────────────────────────────────────────────
const QrGridBackground = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden opacity-[0.03] dark:opacity-[0.05]">
    <div className="absolute inset-0 grid grid-cols-8" style={{ gridTemplateRows: 'repeat(4, 1fr)' }}>
      {Array.from({ length: 32 }).map((_, i) => (
        <div key={i} className="border border-purple-500" style={{ opacity: 0, animation: `qrCellPulse ${3 + (i % 4)}s ease-in-out ${(i * 0.08) % 3}s infinite` }} />
      ))}
    </div>
  </div>
));
QrGridBackground.displayName = 'QrGridBackground';

// ── Particles — CSS ───────────────────────────────────────────────────────────
const ParticlesLayer = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0">
    {PARTICLES.map((p, i) => (
      <div key={i} className="absolute rounded-full bg-purple-400/15 dark:bg-purple-400/10"
        style={{ width: p.width, height: p.height, top: p.top, left: p.left, animation: `particleFloat ${p.duration}s ease-in-out ${p.delay}s infinite` }} />
    ))}
  </div>
));
ParticlesLayer.displayName = 'ParticlesLayer';

// ── Static glow orbs ──────────────────────────────────────────────────────────
const GlowOrbs = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden">
    <div className="absolute -top-32 left-1/2 -translate-x-1/2 w-[500px] h-[500px] rounded-full bg-purple-500/8 dark:bg-purple-500/10 blur-[110px]" />
    <div className="absolute bottom-0 left-1/4 w-[400px] h-[400px] rounded-full bg-indigo-500/8 dark:bg-indigo-500/10 blur-[100px]" />
  </div>
));
GlowOrbs.displayName = 'GlowOrbs';

// ── Section header ────────────────────────────────────────────────────────────
const SectionHeader = memo(({ title, subtitle }) => (
  <div className="mb-5 pb-4 border-b border-gray-100 dark:border-purple-500/10">
    <p className="text-sm font-bold text-gray-800 dark:text-white">{title}</p>
    <p className="text-xs text-gray-400 dark:text-gray-500 mt-0.5">{subtitle}</p>
  </div>
));
SectionHeader.displayName = 'SectionHeader';

// ── Shared action button ──────────────────────────────────────────────────────
const ActionButton = memo(({ onClick, disabled, children, className = '' }) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    className={"rounded-xl bg-purple-600 hover:bg-purple-700 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm font-semibold transition-colors duration-200 " + className}
  >
    {children}
  </button>
));
ActionButton.displayName = 'ActionButton';

// ── Progress bar ──────────────────────────────────────────────────────────────
const ProgressBar = memo(({ progress }) => (
  <div className="space-y-1.5">
    <div className="flex justify-between text-xs text-gray-400">
      <span>Generating...</span><span>{progress}%</span>
    </div>
    <div className="h-1.5 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
      <motion.div
        className="h-full bg-gradient-to-r from-purple-500 to-indigo-500 rounded-full"
        animate={{ width: progress + '%' }}
        transition={{ duration: 0.3 }}
      />
    </div>
  </div>
));
ProgressBar.displayName = 'ProgressBar';

// ══════════════════════════════════════════════════════════════════════════════
// ── 1. BATCH GENERATOR ───────────────────────────────────────────────────────
// ══════════════════════════════════════════════════════════════════════════════
const BatchGenerator = memo(() => {
  const [batchText,    setBatchText]    = useState('');
  const [batchItems,   setBatchItems]   = useState([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress,     setProgress]     = useState(0);

  const itemCount = batchText.split('\n').filter((l) => l.trim()).length;

  const handleGenerate = useCallback(async () => {
    const lines = batchText.split('\n').map((l) => l.trim()).filter(Boolean);
    if (!lines.length) return;
    if (lines.length > 20) { alert('Maximum 20 items per batch.'); return; }

    setIsGenerating(true);
    setProgress(0);
    setBatchItems([]);

    const results = [];
    for (let i = 0; i < lines.length; i++) {
      try {
        results.push({ text: lines[i], dataUrl: await generateQrCanvas(lines[i]), id: Date.now() + i });
      } catch {
        results.push({ text: lines[i], dataUrl: null, id: Date.now() + i });
      }
      setProgress(Math.round(((i + 1) / lines.length) * 100));
    }
    setBatchItems(results);
    setIsGenerating(false);
  }, [batchText]);

  const downloadAll = useCallback(async () => {
    for (let i = 0; i < batchItems.length; i++) {
      if (!batchItems[i].dataUrl) continue;
      await new Promise((r) => setTimeout(r, 150));
      triggerDownload(batchItems[i].dataUrl, 'qronetic-batch-' + (i + 1) + '.png');
    }
  }, [batchItems]);

  return (
    <div className="space-y-5">
      <SectionHeader title="Batch QR Generator" subtitle="Generate up to 20 QR codes at once — one item per line" />
      <div className="space-y-3">
        <textarea
          rows="6" value={batchText}
          onChange={(e) => setBatchText(e.target.value)}
          placeholder={"https://google.com\nhttps://github.com\nHello World"}
          className={INPUT_CLASS + " font-mono resize-none"}
        />
        <div className="flex items-center justify-between">
          <span className="text-xs text-gray-400 dark:text-gray-600">{itemCount} / 20 items</span>
          <ActionButton onClick={handleGenerate} disabled={isGenerating || !batchText.trim()} className="px-5 py-2">
            {isGenerating ? 'Generating...' : '⚡ Generate All'}
          </ActionButton>
        </div>
      </div>

      <AnimatePresence>
        {isGenerating && (
          <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }}>
            <ProgressBar progress={progress} />
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {batchItems.length > 0 && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="space-y-4">
            <div className="flex items-center justify-between">
              <p className="text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wide">{batchItems.length} QR Codes Generated</p>
              <ActionButton onClick={downloadAll} className="text-xs px-3 py-1.5">↓ Download All</ActionButton>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3 max-h-80 overflow-y-auto no-scrollbar">
              {batchItems.map((item, i) => (
                <motion.div key={item.id} initial={{ opacity: 0, scale: 0.92 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: Math.min(i * 0.04, 0.2) }}
                  className="bg-white dark:bg-[#0f0f1a] border border-gray-100 dark:border-purple-500/10 rounded-xl p-2 space-y-2">
                  {item.dataUrl ? (
                    <img src={item.dataUrl} alt={"QR " + (i + 1)} loading="lazy" className="w-full aspect-square object-contain rounded-lg" style={{ imageRendering: 'pixelated' }} />
                  ) : (
                    <div className="w-full aspect-square bg-red-50 dark:bg-red-900/20 rounded-lg flex items-center justify-center">
                      <span className="text-xs text-red-400">Error</span>
                    </div>
                  )}
                  <p className="text-xs text-gray-500 dark:text-gray-400 truncate text-center">{item.text}</p>
                  {item.dataUrl && (
                    <button onClick={() => triggerDownload(item.dataUrl, 'qronetic-' + (i + 1) + '.png')}
                      className="w-full text-xs py-1 rounded-lg bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 hover:bg-purple-100 dark:hover:bg-purple-900/40 transition-colors duration-200">↓</button>
                  )}
                </motion.div>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});
BatchGenerator.displayName = 'BatchGenerator';

// ══════════════════════════════════════════════════════════════════════════════
// ── 2. SVG DOWNLOAD ──────────────────────────────────────────────────────────
// ══════════════════════════════════════════════════════════════════════════════
const SvgDownloader = memo(() => {
  const [text,       setText]       = useState('');
  const [svgContent, setSvgContent] = useState('');
  const [copied,     setCopied]     = useState(false);
  const [isLoading,  setIsLoading]  = useState(false);

  const handleGenerate = useCallback(async () => {
    if (!text.trim()) return;
    setIsLoading(true);
    try { setSvgContent(await generateQrSvg(text)); }
    catch (err) { console.error('SVG error:', err); }
    setIsLoading(false);
  }, [text]);

  const handleDownload = useCallback(() => {
    if (!svgContent) return;
    const url = URL.createObjectURL(new Blob([svgContent], { type: 'image/svg+xml' }));
    triggerDownload(url, 'qronetic-qr-code.svg');
    URL.revokeObjectURL(url);
  }, [svgContent]);

  const handleCopy = useCallback(() => {
    if (!svgContent) return;
    navigator.clipboard.writeText(svgContent).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  }, [svgContent]);

  return (
    <div className="space-y-5">
      <SectionHeader title="SVG Download" subtitle="Download your QR code as a scalable vector graphic — perfect for print" />
      <div className="space-y-3">
        <input type="text" value={text} onChange={(e) => setText(e.target.value)} placeholder="Enter text or URL..." className={INPUT_CLASS} />
        <ActionButton onClick={handleGenerate} disabled={!text.trim() || isLoading} className="w-full py-2.5">
          {isLoading ? 'Generating...' : '⬡ Generate SVG'}
        </ActionButton>
      </div>
      <AnimatePresence>
        {svgContent && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
            <div className="w-48 h-48 mx-auto bg-white rounded-2xl p-3 shadow-sm border border-gray-100" dangerouslySetInnerHTML={{ __html: svgContent }} />
            <div className="flex gap-3">
              <ActionButton onClick={handleDownload} className="flex-1 py-2.5">↓ Download SVG</ActionButton>
              <button onClick={handleCopy}
                className="flex-1 py-2.5 rounded-xl border border-purple-500/30 text-purple-600 dark:text-purple-400 text-sm font-semibold hover:bg-purple-50 dark:hover:bg-purple-900/20 transition-colors duration-200">
                {copied ? '✓ Copied!' : '⎘ Copy SVG'}
              </button>
            </div>
            <div className="bg-gray-50 dark:bg-[#0f0f1a] rounded-xl p-3 max-h-32 overflow-y-auto no-scrollbar border border-gray-200 dark:border-purple-500/10">
              <pre className="text-xs text-gray-500 dark:text-gray-400 font-mono whitespace-pre-wrap break-all">{svgContent.slice(0, 300)}...</pre>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});
SvgDownloader.displayName = 'SvgDownloader';

// ══════════════════════════════════════════════════════════════════════════════
// ── 3. CLIPBOARD COPY ────────────────────────────────────────────────────────
// ══════════════════════════════════════════════════════════════════════════════
const ClipboardCopy = memo(() => {
  const [text,      setText]      = useState('');
  const [copied,    setCopied]    = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [preview,   setPreview]   = useState('');

  const handleGenerate = useCallback(async () => {
    if (!text.trim()) return;
    setIsLoading(true);
    try {
      const dataUrl = await generateQrCanvas(text, 512);
      setPreview(dataUrl);
      const blob = await (await fetch(dataUrl)).blob();
      await navigator.clipboard.write([new ClipboardItem({ 'image/png': blob })]);
      setCopied(true);
      setTimeout(() => setCopied(false), 3000);
    } catch {
      if (preview) { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 3000); }
    }
    setIsLoading(false);
  }, [text, preview]);

  return (
    <div className="space-y-5">
      <SectionHeader title="Copy QR to Clipboard" subtitle="Generate and copy your QR code image directly to clipboard" />
      <div className="space-y-3">
        <input type="text" value={text} onChange={(e) => setText(e.target.value)} placeholder="Enter text or URL..." className={INPUT_CLASS} />
        <ActionButton onClick={handleGenerate} disabled={!text.trim() || isLoading} className="w-full py-2.5">
          {isLoading ? 'Copying...' : copied ? '✓ Copied to Clipboard!' : '⎘ Generate & Copy'}
        </ActionButton>
      </div>
      <AnimatePresence>
        {preview && (
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="flex flex-col items-center gap-3">
            <div className="w-40 h-40 bg-white rounded-2xl p-2 shadow-sm border border-gray-100">
              <img src={preview} alt="QR preview" className="w-full h-full object-contain" style={{ imageRendering: 'pixelated' }} />
            </div>
            <AnimatePresence>
              {copied && (
                <motion.p initial={{ opacity: 0, y: 4 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -4 }}
                  className="text-xs text-green-600 dark:text-green-400 font-medium">
                  ✓ QR code copied to clipboard!
                </motion.p>
              )}
            </AnimatePresence>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});
ClipboardCopy.displayName = 'ClipboardCopy';

// ══════════════════════════════════════════════════════════════════════════════
// ── 4. QR COMPARISON ─────────────────────────────────────────────────────────
// ══════════════════════════════════════════════════════════════════════════════
const QrComparison = memo(() => {
  const [textA,   setTextA]   = useState('');
  const [textB,   setTextB]   = useState('');
  const [canvasA, setCanvasA] = useState('');
  const [canvasB, setCanvasB] = useState('');
  const [loading, setLoading] = useState(false);

  const handleCompare = useCallback(async () => {
    if (!textA.trim() || !textB.trim()) return;
    setLoading(true);
    try {
      const [a, b] = await Promise.all([generateQrCanvas(textA), generateQrCanvas(textB)]);
      setCanvasA(a); setCanvasB(b);
    } catch (err) { console.error('Comparison error:', err); }
    setLoading(false);
  }, [textA, textB]);

  return (
    <div className="space-y-5">
      <SectionHeader title="QR Code Comparison" subtitle="Compare two QR codes side by side" />
      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wide">QR Code A</label>
          <input type="text" value={textA} onChange={(e) => setTextA(e.target.value)} placeholder="First content..." className={INPUT_CLASS} />
        </div>
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wide">QR Code B</label>
          <input type="text" value={textB} onChange={(e) => setTextB(e.target.value)} placeholder="Second content..." className={INPUT_CLASS} />
        </div>
      </div>
      <ActionButton onClick={handleCompare} disabled={!textA.trim() || !textB.trim() || loading} className="w-full py-2.5">
        {loading ? 'Comparing...' : '⚖ Compare QR Codes'}
      </ActionButton>
      <AnimatePresence>
        {canvasA && canvasB && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="grid grid-cols-2 gap-4">
            <div className="space-y-2 text-center">
              <div className="bg-white rounded-xl p-2 shadow-sm border border-gray-100">
                <img src={canvasA} alt="QR A" className="w-full aspect-square object-contain" style={{ imageRendering: 'pixelated' }} />
              </div>
              <p className="text-xs text-gray-500 dark:text-gray-400 truncate font-mono px-1">{textA}</p>
              <span className="inline-block text-xs px-2 py-0.5 rounded-full bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 font-medium">{textA.length} chars</span>
            </div>
            <div className="space-y-2 text-center">
              <div className="bg-white rounded-xl p-2 shadow-sm border border-gray-100">
                <img src={canvasB} alt="QR B" className="w-full aspect-square object-contain" style={{ imageRendering: 'pixelated' }} />
              </div>
              <p className="text-xs text-gray-500 dark:text-gray-400 truncate font-mono px-1">{textB}</p>
              <span className="inline-block text-xs px-2 py-0.5 rounded-full bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 font-medium">{textB.length} chars</span>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});
QrComparison.displayName = 'QrComparison';

// ══════════════════════════════════════════════════════════════════════════════
// ── 5. EXPIRY QR ─────────────────────────────────────────────────────────────
// ══════════════════════════════════════════════════════════════════════════════
const TODAY = new Date().toISOString().split('T')[0];

const ExpiryQr = memo(() => {
  const [text,       setText]       = useState('');
  const [expiryDate, setExpiryDate] = useState('');
  const [canvas,     setCanvas]     = useState('');
  const [isLoading,  setIsLoading]  = useState(false);
  const [expired,    setExpired]    = useState(false);

  const handleGenerate = useCallback(async () => {
    if (!text.trim() || !expiryDate) return;
    setIsLoading(true);
    setExpired(false);
    const expiry = new Date(expiryDate);
    if (expiry < new Date()) { setExpired(true); setIsLoading(false); return; }
    try {
      const qrText = text + '\n[Expires: ' + expiry.toLocaleDateString() + ']';
      setCanvas(await generateQrCanvas(qrText));
    } catch (err) { console.error('Expiry QR error:', err); }
    setIsLoading(false);
  }, [text, expiryDate]);

  const handleDownload = useCallback(() => {
    if (canvas) triggerDownload(canvas, 'qronetic-expiry-qr.png');
  }, [canvas]);

  return (
    <div className="space-y-5">
      <SectionHeader title="QR with Expiry Label" subtitle="Embed an expiry date into your QR code content" />
      <div className="space-y-3">
        <input type="text" value={text} onChange={(e) => setText(e.target.value)} placeholder="Enter text or URL..." className={INPUT_CLASS} />
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wide">Expiry Date</label>
          <input type="date" value={expiryDate} onChange={(e) => setExpiryDate(e.target.value)} min={TODAY} className={INPUT_CLASS + " cursor-pointer"} />
        </div>
        <ActionButton onClick={handleGenerate} disabled={!text.trim() || !expiryDate || isLoading} className="w-full py-2.5">
          {isLoading ? 'Generating...' : '📅 Generate with Expiry'}
        </ActionButton>
      </div>
      <AnimatePresence>
        {expired && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-500/20 rounded-xl px-4 py-3">
            <p className="text-sm text-red-600 dark:text-red-400 text-center">Selected date is in the past. Please choose a future date.</p>
          </motion.div>
        )}
        {canvas && !expired && (
          <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="flex flex-col items-center gap-3">
            <div className="w-48 h-48 bg-white rounded-2xl p-2 shadow-sm border border-gray-100">
              <img src={canvas} alt="Expiry QR" className="w-full h-full object-contain" style={{ imageRendering: 'pixelated' }} />
            </div>
            <p className="text-xs text-gray-500 dark:text-gray-400">📅 Expires: {expiryDate && new Date(expiryDate).toLocaleDateString()}</p>
            <ActionButton onClick={handleDownload} className="px-5 py-2">↓ Download</ActionButton>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});
ExpiryQr.displayName = 'ExpiryQr';

// ── Utility tab button ────────────────────────────────────────────────────────
const UtilTabButton = memo(({ id, label, emoji, isActive, onClick }) => (
  <button
    type="button"
    onClick={() => onClick(id)}
    className={
      "flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold border-2 transition-colors duration-200 " +
      (isActive
        ? "border-purple-500 bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400"
        : "border-gray-200 dark:border-gray-700 text-gray-500 hover:border-purple-400/50 bg-white dark:bg-[#1a1a2e]")
    }
  >
    <span>{emoji}</span> {label}
  </button>
));
UtilTabButton.displayName = 'UtilTabButton';

// ── Main QrUtilities ──────────────────────────────────────────────────────────
const QrUtilities = memo(() => {
  const [activeUtil, setActiveUtil] = useState('batch');

  const setUtil = useCallback((id) => setActiveUtil(id), []);

  return (
    <motion.section
      id="utilities"
      aria-labelledby="utilities-heading"
      {...sectionAnim}
      className="relative w-full px-6 md:px-16 lg:px-24 py-24 bg-gray-50 dark:bg-[#0f0f1a] transition-colors duration-500 overflow-hidden"
    >
      <QrGridBackground />
      <ParticlesLayer />
      <GlowOrbs />

      <div className="relative z-10 max-w-3xl mx-auto">

        {/* Header */}
        <motion.div {...headerAnim} className="mb-12">
          <motion.p {...labelAnim} className="text-sm font-semibold uppercase tracking-widest text-purple-500 dark:text-purple-400 mb-2">
            Utilities
          </motion.p>
          <h2 id="utilities-heading" className="text-4xl md:text-5xl font-bold text-gray-900 dark:text-white tracking-tight">
            Power Tools
          </h2>
          <motion.div {...underlineAnim} className="mt-1 h-1 w-16 bg-gradient-to-r from-purple-500 to-indigo-500 rounded-full" />
          <p className="mt-4 text-gray-500 dark:text-gray-400 text-base max-w-xl">
            Advanced tools for power users — batch generation, SVG export, clipboard copy, comparison, and more.
          </p>
        </motion.div>

        {/* Tab bar */}
        <div className="flex gap-2 flex-wrap mb-6">
          <UtilTabButton id="batch"     label="Batch"     emoji="⚡" isActive={activeUtil === 'batch'}     onClick={setUtil} />
          <UtilTabButton id="svg"       label="SVG"       emoji="⬡" isActive={activeUtil === 'svg'}       onClick={setUtil} />
          <UtilTabButton id="clipboard" label="Clipboard" emoji="⎘" isActive={activeUtil === 'clipboard'} onClick={setUtil} />
          <UtilTabButton id="compare"   label="Compare"   emoji="⚖" isActive={activeUtil === 'compare'}   onClick={setUtil} />
          <UtilTabButton id="expiry"    label="Expiry"    emoji="📅" isActive={activeUtil === 'expiry'}    onClick={setUtil} />
        </div>

        {/* Content card */}
        <div className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-6 shadow-sm">
          <AnimatePresence mode="wait">
            {activeUtil === 'batch'     && <motion.div key="batch"     {...tabAnim}><BatchGenerator /></motion.div>}
            {activeUtil === 'svg'       && <motion.div key="svg"       {...tabAnim}><SvgDownloader /></motion.div>}
            {activeUtil === 'clipboard' && <motion.div key="clipboard" {...tabAnim}><ClipboardCopy /></motion.div>}
            {activeUtil === 'compare'   && <motion.div key="compare"   {...tabAnim}><QrComparison  /></motion.div>}
            {activeUtil === 'expiry'    && <motion.div key="expiry"    {...tabAnim}><ExpiryQr      /></motion.div>}
          </AnimatePresence>
        </div>

      </div>
    </motion.section>
  );
});

QrUtilities.displayName = 'QrUtilities';
export default QrUtilities;